import{_ as e,a}from"./chunks/频繁报错提示.B4wBXruJ.js";import{_ as i,o as s,c as d,a2 as l}from"./chunks/framework.DnrXFDHb.js";const g=JSON.parse('{"title":"د User Rate Limits","description":"","frontmatter":{},"headers":[],"relativePath":"ps/Safety/user-rate-limits.md","filePath":"ps/Safety/user-rate-limits.md","lastUpdated":1781962217000}'),r={name:"ps/Safety/user-rate-limits.md"};function o(p,t,u,n,c,m){return s(),d("div",null,[...t[0]||(t[0]=[l('<h1 id="د-user-rate-limits" tabindex="-1">د User Rate Limits <a class="header-anchor" href="#د-user-rate-limits" aria-label="Permalink to &quot;د User Rate Limits&quot;">​</a></h1><p>User rate limits کنټرولوي چې عادي users یا visitors له homepage څخه څو ځله files upload کولای شي. دا د public upload pages د ناوړه کارونې مخنیوي کې مرسته کوي.</p><p>دا feature یوازې homepage uploads اغېزمنوي. Admin uploads او د API Tokens له لارې uploads د user rate limits له خوا نه محدودېږي.</p><h2 id="چېرته-یې-تنظیم-کړئ" tabindex="-1">چېرته یې تنظیم کړئ <a class="header-anchor" href="#چېرته-یې-تنظیم-کړئ" aria-label="Permalink to &quot;چېرته یې تنظیم کړئ&quot;">​</a></h2><p>admin panel پرانیزئ، بیا دې ځای ته لاړ شئ:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Security Settings -&gt; Upload Management -&gt; User Rate Limits</span></span></code></pre></div><p><img src="'+e+'" alt="User rate limit settings" loading="lazy"></p><h2 id="rate-limits-فعالول" tabindex="-1">Rate Limits فعالول <a class="header-anchor" href="#rate-limits-فعالول" aria-label="Permalink to &quot;Rate Limits فعالول&quot;">​</a></h2><p>کله چې <code>Enable Rate Limits</code> فعال شي، ImgBed وروستي uploads د uploader IP address له مخې track کوي.</p><p>Default values:</p><table tabindex="0"><thead><tr><th>Setting</th><th>Default</th><th>تشریح</th></tr></thead><tbody><tr><td>Detection window</td><td>1.5 hours</td><td>upload records څو شاته وخت پورې شمېرل کېږي.</td></tr><tr><td>Max file count</td><td>20</td><td>په detection window کې د allowed files اعظمي شمېر.</td></tr><tr><td>Single file size limit</td><td>20 MB</td><td>د یوه file اعظمي size.</td></tr><tr><td>Total upload size limit</td><td>200 MB</td><td>په detection window کې د upload ټول اعظمي size.</td></tr></tbody></table><p>د بېلګې په توګه، که window 1.5 hours وي، 20 files، هر file 20 MB، او total 200 MB وي، له هماغه IP څخه uploads هغه وخت block کېږي چې له ټاکل شوو limits څخه کوم یو واوړي.</p><h2 id="د-file-types-منع-کول" tabindex="-1">د File Types منع کول <a class="header-anchor" href="#د-file-types-منع-کول" aria-label="Permalink to &quot;د File Types منع کول&quot;">​</a></h2><p><code>Excluded upload file types</code> عادي users یا visitors له ټاکلو file categories upload کولو منع کوي.</p><p>شته categories:</p><table tabindex="0"><thead><tr><th>Type</th><th>تشریح</th></tr></thead><tbody><tr><td>Images</td><td>jpg, png, webp, gif او ورته image files</td></tr><tr><td>Videos</td><td>mp4, webm, mov او ورته video files</td></tr><tr><td>Audio</td><td>mp3, flac, wav او ورته audio files</td></tr><tr><td>Documents</td><td>pdf, txt, md, docx او ورته document files</td></tr><tr><td>Other</td><td>له پورته categories بهر files، لکه zip, rar, exe, apk</td></tr></tbody></table><p>په default ډول type نه وي selected، یعنې allowed دی.</p><p>پر type کلیک کول یې highlight کوي، یعنې هغه type block شوی دی.</p><p>که <code>Other</code> selected وي، visitors چې zip یا rar files upload کوي block کېږي او ورته ویل کېږي چې دا file type supported نه دی.</p><h2 id="block-messages" tabindex="-1">Block Messages <a class="header-anchor" href="#block-messages" aria-label="Permalink to &quot;Block Messages&quot;">​</a></h2><p>کله چې limit trigger شي، users ورته مناسب message ویني:</p><p><img src="'+a+'" alt="Too frequent upload message" loading="lazy"></p><table tabindex="0"><thead><tr><th>Scenario</th><th>د message معنا</th></tr></thead><tbody><tr><td>Single file too large</td><td>file ډېر لوی دی او له upload مخکې باید compressed شي.</td></tr><tr><td>File type blocked</td><td>دا file type supported نه دی. لرې یې کړئ او بیا هڅه وکړئ.</td></tr><tr><td>Uploads too frequent</td><td>وروستي uploads ډېر frequent دي، retry time هم ښکاره کېږي.</td></tr><tr><td>Total size too high</td><td>د وروستیو uploads ټول size ډېر لوړ دی، retry time هم ښکاره کېږي.</td></tr></tbody></table><h2 id="کله-یې-فعال-کړئ" tabindex="-1">کله یې فعال کړئ <a class="header-anchor" href="#کله-یې-فعال-کړئ" aria-label="Permalink to &quot;کله یې فعال کړئ&quot;">​</a></h2><p>که ستاسو upload homepage public access ولري، user rate limits فعال کړئ.</p><p>عام دلیلونه:</p><ul><li>د scripted bulk uploads په اړه اندېښنه لرئ.</li><li>غواړئ د visitors لوی uploads محدود کړئ.</li><li>غواړئ عادي users یوازې images upload کړي، archives یا installers نه.</li><li>غواړئ public upload فعال پاتې شي خو resource usage کنټرول شي.</li></ul><p>که site یوازې ستاسو لپاره وي، یا یوازې administrators upload کوي، دا disabled پرېښودلای شئ.</p>',28)])])}const b=i(r,[["render",o]]);export{g as __pageData,b as default};
